// TestMetricsForwarder_MessageFormat tests the JSON message format
func TestMetricsForwarder_MessageFormat(t *testing.T) {
	var publishedData []byte
	var publishMu sync.Mutex

	mockNATS := &metricsForwarderMockNATS{
		publishFunc: func(ctx context.Context, subject string, data []byte) error {
			publishMu.Lock()
			defer publishMu.Unlock()
			if len(publishedData) == 0 {
				publishedData = data
			}
			return nil
		},
	}

	registry := metric.NewMetricsRegistry()

	// Create test counter with component label
	counter := prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "test_messages_total",
			Help: "Test counter",
		},
		[]string{"component", "status"},
	)

	registry.PrometheusRegistry().MustRegister(counter)
	counter.With(prometheus.Labels{"component": "test-input", "status": "success"}).Add(123)

	forwarder := createTestMetricsForwarder(t, "100ms", mockNATS, registry)

	ctx := context.Background()
	err := forwarder.Start(ctx)
	require.NoError(t, err)

	// Wait for publish cycle
	time.Sleep(150 * time.Millisecond)

	err = forwarder.Stop(1 * time.Second)
	require.NoError(t, err)

	// Verify message format
	publishMu.Lock()
	defer publishMu.Unlock()

	require.NotEmpty(t, publishedData, "should have published data")

	var entry map[string]interface{}
	err = json.Unmarshal(publishedData, &entry)
	require.NoError(t, err)

	// Verify required fields
	assert.Contains(t, entry, "timestamp", "should include timestamp")
	assert.Contains(t, entry, "name", "should include name")
	assert.Contains(t, entry, "component", "should include component")
	assert.Contains(t, entry, "type", "should include type")
	assert.Contains(t, entry, "value", "should include value")
	assert.Contains(t, entry, "labels", "should include labels")

	// Verify timestamp is a valid number
	timestamp, ok := entry["timestamp"].(float64)
	assert.True(t, ok, "timestamp should be a number")
	assert.Greater(t, timestamp, float64(0), "timestamp should be positive")

	// Verify type is one of the valid metric types
	metricType, ok := entry["type"].(string)
	assert.True(t, ok, "type should be a string")
	assert.Contains(t, []string{"counter", "gauge", "histogram", "summary", "untyped"},
		metricType, "type should be a valid metric type")

	// Verify labels is an object
	_, ok = entry["labels"].(map[string]interface{})
	assert.True(t, ok, "labels should be an object")
}

// TestMetricsForwarder_ExtractComponent tests component extraction from labels
func TestMetricsForwarder_ExtractComponent(t *testing.T) {
	tests := []struct {
		name          string
		labels        map[string]string
		wantComponent string
	}{
		{
			name:          "extracts component from labels",
			labels:        map[string]string{"component": "processor"},
			wantComponent: "processor",
		},
		{
			name:          "falls back to system when no component label",
			labels:        map[string]string{"status": "active"},
			wantComponent: "system",
		},
		{
			name:          "handles empty labels",
			labels:        map[string]string{},
			wantComponent: "system",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var publishedData []byte
			var publishMu sync.Mutex
			testMetricName := "test_extract_component_metric"

			mockNATS := &metricsForwarderMockNATS{
				publishFunc: func(ctx context.Context, subject string, data []byte) error {
					// Only capture our test metric, not other metrics from the registry
					var entry map[string]interface{}
					if err := json.Unmarshal(data, &entry); err == nil {
						if entry["name"] == testMetricName {
							publishMu.Lock()
							if len(publishedData) == 0 {
								publishedData = data
							}
							publishMu.Unlock()
						}
					}
					return nil
				},
			}

			// Use mock gatherer to have full control over what metrics are returned
			metricType := dto.MetricType_COUNTER
			value := float64(1)

			// Build labels for the metric
			var metricLabels []*dto.LabelPair
			for k, v := range tt.labels {
				name := k
				val := v
				metricLabels = append(metricLabels, &dto.LabelPair{Name: &name, Value: &val})
			}

			mockGatherer := &mockMetricsRegistry{
				gatherFunc: func() ([]*dto.MetricFamily, error) {
					return []*dto.MetricFamily{
						{
							Name: &testMetricName,
							Type: &metricType,
							Metric: []*dto.Metric{
								{
									Label:   metricLabels,
									Counter: &dto.Counter{Value: &value},
								},
							},
						},
					}, nil
				},
			}

			config := &MetricsForwarderConfig{
				PushInterval: "100ms",
			}

			forwarder, err := newMetricsForwarderForTestWithMockRegistry(config, mockNATS, mockGatherer)
			require.NoError(t, err)

			ctx := context.Background()
			err = forwarder.Start(ctx)
			require.NoError(t, err)

			// Wait for publish cycle
			time.Sleep(150 * time.Millisecond)

			err = forwarder.Stop(1 * time.Second)
			require.NoError(t, err)

			// Verify component extraction
			publishMu.Lock()
			defer publishMu.Unlock()

			require.NotEmpty(t, publishedData, "should have published the test metric")

			var entry map[string]interface{}
			err = json.Unmarshal(publishedData, &entry)
			require.NoError(t, err)

			assert.Equal(t, tt.wantComponent, entry["component"])
		})
	}
}

