// TestMetricsForwarder_ConcurrentGather tests thread-safety of concurrent metric gathering
func TestMetricsForwarder_ConcurrentGather(t *testing.T) {
	publishCount := 0
	var publishMu sync.Mutex

	mockNATS := &metricsForwarderMockNATS{
		publishFunc: func(ctx context.Context, subject string, data []byte) error {
			publishMu.Lock()
			defer publishMu.Unlock()
			publishCount++
			return nil
		},
	}

	registry := metric.NewMetricsRegistry()

	// Create counter
	counter := prometheus.NewCounter(prometheus.CounterOpts{
		Name: "test_counter",
		Help: "Test counter",
	})
	registry.PrometheusRegistry().MustRegister(counter)

	forwarder := createTestMetricsForwarder(t, "50ms", mockNATS, registry)

	ctx := context.Background()
	err := forwarder.Start(ctx)
	require.NoError(t, err)

	// Concurrently modify metrics while publishing
	var wg sync.WaitGroup
	wg.Add(10)

	for i := 0; i < 10; i++ {
		go func() {
			defer wg.Done()
			for j := 0; j < 10; j++ {
				counter.Inc()
				time.Sleep(5 * time.Millisecond)
			}
		}()
	}

	// Wait for goroutines and some publish cycles
	wg.Wait()
	time.Sleep(150 * time.Millisecond)

	err = forwarder.Stop(1 * time.Second)
	require.NoError(t, err)

	// Verify publishes occurred
	publishMu.Lock()
	defer publishMu.Unlock()
	assert.Greater(t, publishCount, 0, "should have published metrics")
}

