// Helper: convert label map to slice of keys
func labelsToSlice(labels map[string]string) []string {
	if len(labels) == 0 {
		return []string{}
	}
	keys := make([]string, 0, len(labels))
	for k := range labels {
		keys = append(keys, k)
	}
	return keys
}

// metricsForwarderMockNATS implements a minimal NATS client interface for testing
type metricsForwarderMockNATS struct {
	publishFunc func(ctx context.Context, subject string, data []byte) error
}

func (m *metricsForwarderMockNATS) PublishToStream(ctx context.Context, subject string, data []byte) error {
	if m.publishFunc != nil {
		return m.publishFunc(ctx, subject, data)
	}
	return nil
}

// mockMetricsRegistry implements a mock MetricsGatherer for testing error cases
type mockMetricsRegistry struct {
	gatherFunc func() ([]*dto.MetricFamily, error)
}

func (m *mockMetricsRegistry) Gather() ([]*dto.MetricFamily, error) {
	if m.gatherFunc != nil {
		return m.gatherFunc()
	}
	return []*dto.MetricFamily{}, nil
}
